package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonReader_isLiteral_Test {

  private JsonReader jsonReader;
  private Method isLiteralMethod;
  private Method checkLenientMethod;

  @BeforeEach
  void setUp() throws NoSuchMethodException {
    // Mock Reader since JsonReader requires it but isLiteral does not use it
    Reader mockReader = mock(Reader.class);
    jsonReader = new JsonReader(mockReader);

    // Access private method isLiteral(char)
    isLiteralMethod = JsonReader.class.getDeclaredMethod("isLiteral", char.class);
    isLiteralMethod.setAccessible(true);

    // Access private method checkLenient()
    checkLenientMethod = JsonReader.class.getDeclaredMethod("checkLenient");
    checkLenientMethod.setAccessible(true);
  }

  private boolean invokeIsLiteral(char c) throws Throwable {
    try {
      return (boolean) isLiteralMethod.invoke(jsonReader, c);
    } catch (InvocationTargetException e) {
      // Unwrap IOException thrown by isLiteral
      throw e.getCause();
    }
  }

  private void verifyCheckLenientCalled(Object spyReader) throws Exception {
    // Verify that checkLenient() was called once on spyReader by using reflection
    // We'll track invocations by overriding checkLenient via Mockito spy and verify via spy's internal Mockito data
    // Since direct verify(spyReader).checkLenient() is not possible (private method),
    // we use Mockito's verify(spyReader, times(1)) via reflection on the spy's invocation handler.

    // Alternative approach: use Mockito's verify with a wrapper spy class that exposes checkLenient
    // But here, we simulate by invoking checkLenient and catching if it was called

    // Instead, we can verify by spying on the checkLenientMethod via Mockito's verify on a wrapper method.
    // Since this is complicated, the simplest way is to count invocations using Mockito's mocking details.

    // However, Mockito does not track private method calls for verification.
    // So we use a workaround: create a subclass that overrides checkLenient and counts calls.

    // This method is a placeholder. Actual verification is done in the test method below.
  }

  @Test
  void testIsLiteral_returnsFalseForCharsThatReturnFalseWithoutLenientCheck() throws Throwable {
    // Characters that return false without calling checkLenient()
    char[] chars = {
        '{', '}', '[', ']', ':', ',', ' ', '\t', '\f', '\r', '\n'
    };
    for (char c : chars) {
      assertFalse(invokeIsLiteral(c), "Expected false for char: '" + c + "'");
    }
  }

  @Test
  void testIsLiteral_callsCheckLenientAndReturnsFalseForLenientChars() throws Throwable {
    // Characters that call checkLenient() then fall through to return false
    char[] chars = {'/', '\\', ';', '#', '='};

    // Create a subclass of JsonReader to override checkLenient and track calls
    class JsonReaderSpy extends JsonReader {
      int checkLenientCallCount = 0;

      JsonReaderSpy(Reader in) {
        super(in);
      }

      @Override
      protected void finalize() throws Throwable {
        super.finalize();
      }

      @Override
      void checkLenient() throws IOException {
        checkLenientCallCount++;
        super.checkLenient();
      }
    }

    JsonReaderSpy spyReader = new JsonReaderSpy(mock(Reader.class));

    // Use reflection to access the private isLiteral method on spyReader
    for (char c : chars) {
      boolean result;
      try {
        result = (boolean) isLiteralMethod.invoke(spyReader, c);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
      assertFalse(result, "Expected false for char: '" + c + "'");

      // Verify that checkLenient() was called once
      assertEquals(1, spyReader.checkLenientCallCount, "Expected checkLenient() to be called once for char: '" + c + "'");

      // Reset count for next iteration
      spyReader.checkLenientCallCount = 0;
    }
  }

  @Test
  void testIsLiteral_returnsTrueForOtherChars() throws Throwable {
    // Characters that should return true (not in any case above)
    char[] chars = {
        'a', 'Z', '0', '9', '_', '+', '-', '*', '%', '@', '^', '!', '`', '~'
    };
    for (char c : chars) {
      assertTrue(invokeIsLiteral(c), "Expected true for char: '" + c + "'");
    }
  }

  @Test
  void testIsLiteral_checkLenientThrowsIOException() throws Throwable {
    // Create a subclass of JsonReader to override checkLenient and throw IOException
    class JsonReaderSpy extends JsonReader {
      JsonReaderSpy(Reader in) {
        super(in);
      }

      @Override
      void checkLenient() throws IOException {
        throw new IOException("lenient check failed");
      }
    }

    JsonReaderSpy spyReader = new JsonReaderSpy(mock(Reader.class));

    char[] chars = {'/', '\\', ';', '#', '='};
    for (char c : chars) {
      try {
        isLiteralMethod.invoke(spyReader, c);
        fail("Expected IOException for char: '" + c + "'");
      } catch (InvocationTargetException e) {
        Throwable cause = e.getCause();
        assertTrue(cause instanceof IOException);
        assertEquals("lenient check failed", cause.getMessage());
      }
    }
  }
}
